insert into regulations (slug, title, category, summary, doc_number, authority, issued_date, status, status_note, source_url, source_filename, relevance, sort_order, published, featured, file_size_kb, download_url) values ('so-2488-2026-appellate-authority-mines', 'S.O. 2488(E) — Appellate authority for mines under the OSH&WC Code', 'dgms_notification', 'Under section 111(3) of the OSH&WC Code 2020, the Central Government appoints the Gazetted officers to be the appellate authority for the purposes of the Code in the case of mines.', 'S.O. 2488(E)', 'Ministry of Labour & Employment', '2026-05-13', 'in_force', 'Made under the Occupational Safety, Health and Working Conditions Code, 2020.', 'https://www.dgms.gov.in/writereaddata/UploadFile/Gz2_22072026.pdf', 'Gz2_22072026.pdf', 2, 320, true, false, 595, 'https://docs.mangalamcoal.com/regs/so-2488-2026-appellate-authority-mines.pdf')
