insert into regulations (slug, title, category, summary, doc_number, authority, issued_date, status, status_note, source_url, source_filename, relevance, sort_order, published, featured, file_size_kb, download_url) values ('so-2515-2026-inspector-cum-facilitator-appointments', 'S.O. 2515(E) — Appointment of Inspectors-cum-Facilitators of Mines', 'dgms_notification', 'Under section 34(1) of the OSH&WC Code 2020, the Central Government appoints officers of the Directorate General of Mines Safety to be Inspector-cum-Facilitator of Mines, subordinate to the Chief Inspector-cum-Facilitator, superseding several earlier appointment notifications from 2002 onward.', 'S.O. 2515(E)', 'Ministry of Labour & Employment', '2026-05-13', 'in_force', 'Made under the Occupational Safety, Health and Working Conditions Code, 2020.', 'https://www.dgms.gov.in/writereaddata/UploadFile/Gz1_22072026.pdf', 'Gz1_22072026.pdf', 2, 320, true, false, 274, 'https://docs.mangalamcoal.com/regs/so-2515-2026-inspector-cum-facilitator-appointments.pdf')
