insert into regulations (slug, title, category, summary, doc_number, authority, issued_date, status, status_note, source_url, source_filename, relevance, sort_order, published, featured, file_size_kb, download_url) values ('so-2517-2026-five-hour-continuous-work-interval', 'S.O. 2517(E) — Maximum five hours'' continuous work with a half-hour interval', 'dgms_notification', 'Under section 25(1)(b) of the OSH&WC Code 2020, the Central Government notifies that no person shall work more than five hours continuously without an interval of at least half an hour.', 'S.O. 2517(E)', 'Ministry of Labour & Employment', '2026-05-13', 'in_force', 'Made under the Occupational Safety, Health and Working Conditions Code, 2020.', 'https://www.dgms.gov.in/writereaddata/UploadFile/Gz3_22072026.pdf', 'Gz3_22072026.pdf', 2, 320, true, false, 461, 'https://docs.mangalamcoal.com/regs/so-2517-2026-five-hour-continuous-work-interval.pdf')
